def process(d, x, y, z, flag, opt, mode, retries, timeout, limit, offset):
    if flag:
        if mode == 1:
            for i in range(len(d)):
                if d[i] > x:
                    if d[i] < y:
                        if z:
                            result = d[i] * 2
                            if result > limit:
                                result = limit
                            return result
    return None

